}
i_tmp=i;

while((n_temp=n3.exec(result))!=null){
//获取每话的标题
n_sub=n_temp[1];
//判断VIP
if((n_sub.match(/span/))!=null){
n_sub=n_sub.match(/span>(.+)<\/span><spa/)[1];n_sub='🔒'+n_sub;
}
//给每话的标题添加卷标题
if(p[0]!=null){
i=i_tmp;
p_tmp=p[i].w;
while(p_tmp>n3.lastIndex){
i=i-1;
p_tmp=p[i].w;
}
n_pre=p[i].q;
n_pre=n_pre+' | ';
}
//保存数据到数组
n=n_pre+n_sub;
t=t+1;
